exercise_kb('EX_BW_303', 'walking_lunges', 1, [], ['knees', 'hips'], ['unilateral_stability', 'knee_tracking'], ['foundation', 'build_and_burn', 'recomposition_1', 'recomposition_2', 'hypertrophy_volume', 'peak_metabolic'], ['quads', 'glutes'], ['hamstrings', 'core_stabilization'], ['a_tier', 'a_tier'], 'unilateral_leg', true, 'The walking lunge is a lower-body exercise that targets the glutes, quads, and hamstrings while challenging stability and balance. It can be performed for reps, time, or distance in the lower-body portion of any workout.', 'BYe4uyGF-h4').
