exercise_kb('EX_104', '45_degree_back_extension', 2, ['back_extension_machine'], ['lumbar_shear'], ['lower_back_strengthening'], ['foundation', 'build_and_burn', 'recomposition', 'recomposition', 'hypertrophy_volume'], ['glutes', 'hamstrings'], ['lower_back'], ['s_tier'], 'hinge_pattern', true, 'The back extension is an exercise used to build lower back strength that also targets the hamstrings and glutes. It is often performed on a 45-degree bench with the feet anchored. Unweighted back extensions are often performed for high reps, such as 15-20 reps or more, but the movement can also be performed with added weight in lower rep ranges, such as 8-12 reps per set.', 'VH4Bqn1FUhM').
exercise_kb('EX_105', 'hack_squat', 3, ['hack_squat_machine'], ['high_knee_torque'], [], ['recomposition', 'recomposition', 'hypertrophy_volume', 'strength_block'], ['quads'], ['glutes'], ['s_tier'], 'squat_pattern', true, 'The hack squat is a machine-based exercise that targets the muscles of the legs, particularly the quadriceps. It is often used as an accessory for squats, but can also be the main lower-body movement in a workout. It is often performed for moderate to high reps, such as 8-12 reps per set or more.', 'g9i05umL5vc').
exercise_kb('EX_106', 'barbell_back_squat', 2, ['barbell', 'squat_rack', 'weight_plates'], ['spinal_compression', 'high_knee_torque'], [], ['foundation', 'recomposition', 'recomposition', 'strength_block', 'hypertrophy_volume', 'strength_block'], ['quads', 'glutes'], ['core', 'lower_back'], ['s_tier', 'a_tier'], 'squat_pattern', true, 'The barbell back squat to box is a popular version of a classic lower-body exercise that utilizes a box at the bottom position of the movement. This allows the lifter to customize the depth of the squat, as well as limit the stretch reflex at the bottom of the squat. The movement targets the quadriceps, glutes, and hamstrings. The squat to box can be performed for low reps to build strength or power, or for higher reps to build muscle.', '4D8wjuk7IVk').
exercise_kb('EX_107', 'bulgarian_split_squat', 1, ['dumbbells', 'bench'], ['high_knee_torque'], [], ['foundation', 'recomposition', 'recomposition', 'strength_block', 'hypertrophy_volume', 'strength_block'], ['quads', 'glutes'], ['hamstrings', 'core'], ['s_tier', 'a_tier'], 'unilateral_leg', true, 'The dumbbell Bulgaria split squat is a single-leg exercise targeting the quads, glutes, and hamstrings.', 'or1frhkjBDc').
exercise_kb('EX_108', 'pendulum_squat', 3, ['pendulum_squat_machine'], ['extreme_knee_torque'], [], ['recomposition', 'recomposition', 'hypertrophy_volume', 'strength_block'], ['quads'], ['glutes'], ['s_tier'], 'squat_pattern', true, 'The jump squat is an explosive bodyweight exercise targeting the quads, hamstrings, and glutes. It is also a serious cardiovascular challenge when done for reps. It can be performed as a power exercise to build jumping power, or in any fat-loss or athleticism-focused workout.', 'RE9k04SVWOo').
exercise_kb('EX_109', 'smith_machine_squat', 2, ['smith_machine', 'weight_plates'], ['spinal_compression', 'knee_torque'], [], ['foundation', 'recomposition', 'recomposition', 'hypertrophy_volume'], ['quads', 'glutes'], ['core'], ['s_tier', 'a_tier'], 'squat_pattern', true, 'The Smith machine box squat is a machine-based exercise targeting the quads, glutes, and hamstrings. The Smith machine mimics a barbell but provides more stability. This movement can be programmed in low reps for strength or power or higher reps for muscle and strength endurance. It is often performed for moderate to high reps, such as 8-12 reps per set or more, as part of a full-body or lower-body workout.', 'iKCJCydYYrE').
exercise_kb('EX_110', 'hip_thrust_machine', 3, ['hip_thrust_machine'], [], [], ['recomposition', 'recomposition', 'hypertrophy_volume', 'strength_block'], ['glutes'], ['hamstrings'], ['a_tier'], 'glute_isolation', true, 'The dip machine is a machine exercise that mimics a triceps dip, a bodyweight exercise performed on parallel bars or on a pull-up and dip station. It targets the triceps first, but also stretches and strengthens the chest and shoulders. Dips with a triceps focus are usually performed with an upright torso, the knees bent and crossed, and the arms close to the body. Dips can be performed for low reps for strength or higher reps for muscle growth.', 'e7_zkMK53AU').
