exercise_kb('EX_114', 'smith_machine_lunge', 2, ['smith_machine'], ['knee_torque'], [], ['recomposition', 'recomposition', 'hypertrophy_volume'], ['glutes', 'quads'], ['hamstrings'], ['a_tier'], 'unilateral_leg', true, 'The Smith machine lunge squat is an exercise targeting the quads, glutes, and hamstrings. Using added weight allows you to overload the exercise beyond body weight and perform the movement in strength ranges. The Smith machine mimics a barbell but provides more stability.', 'H4rbpNsgyvs').
exercise_kb('EX_115', 'romanian_deadlift', 2, ['barbell', 'weight_plates'], ['spinal_compression', 'lumbar_shear'], [], ['foundation', 'recomposition', 'strength_block', 'hypertrophy_volume', 'strength_block'], ['glutes', 'hamstrings'], ['lower_back', 'core'], ['a_tier'], 'hinge_pattern', true, 'The barbell stiff-legged deadlift targets the hamstrings, glutes, lower and upper back, as well as the core. It is a popular accessory movement for the deadlift, but also a muscle-building hamstring movement.', '5rIqP63yWFg').
exercise_kb('EX_116', 'leg_extension', 2, ['leg_extension_machine'], ['patellar_tendon_stress'], [], ['build_and_burn', 'build_and_burn', 'recomposition', 'recomposition', 'hypertrophy_volume'], ['quads'], [], ['a_tier'], 'quad_isolation', false, 'The leg extension is a popular machine-based exercise for the legs, particularly the quadriceps. It is usually performed for moderate to high reps, such as 8-12 reps per set or more, as part of a leg pre-exhaust or as a muscle-building movement for lower-body training.', 'w72YiHz15CA').
exercise_kb('EX_117', 'barbell_front_squat', 2, ['barbell', 'squat_rack', 'weight_plates'], ['spinal_compression', 'wrist_strain', 'knee_torque'], [], ['foundation', 'recomposition', 'recomposition', 'strength_block', 'strength_block'], ['quads', 'core'], ['glutes', 'upper_back'], ['a_tier'], 'squat_pattern', true, 'The barbell front squat is a compound movement that emphasizes building the lower-body muscle groups. With the barbell racked in front of the body on the anterior delts, the front squat emphasizes the quads and glutes, but also upper back and core strength to remain upright. Front squats can be trained as an alternative to back squats, as an accessory movement for either squats or deadlifts, or for strength and muscle on their own. Many lifters and athletes prefer them to back squats, although they can be uncomfortable and difficult to learn at first.', '_qv0m3tPd3s').
exercise_kb('EX_118', 'low_bar_back_squat', 2, ['barbell', 'squat_rack', 'weight_plates'], ['spinal_compression', 'shoulder_mobility_strain'], [], ['foundation', 'strength_block', 'strength_block'], ['quads', 'glutes', 'lower_back'], ['hamstrings', 'core'], ['a_tier'], 'squat_pattern', true, 'The barbell back squat is a popular compound movement that emphasizes building the lower-body muscle groups and overall strength. It''s the classic way to start a leg day, and is a worthy centerpiece to a lower-body training program. The squat is a competitive lift in the sport of powerlifting, but is also a classic measurement of lower-body strength. With the barbell racked on the traps or upper back, the emphasis is placed on the posterior chain but the entire body gets worked. The back squat can be trained in everything from heavy singles to sets of 20 reps or higher.', 'BeM2oyJ0W0E').
exercise_kb('EX_119', '45_degree_leg_press', 2, ['leg_press_machine'], ['lumbar_flexion_if_deep'], [], ['foundation', 'recomposition', 'recomposition', 'hypertrophy_volume', 'strength_block'], ['quads', 'glutes'], ['hamstrings'], ['a_tier'], 'squat_pattern', true, 'The leg press is a machine exercise targeting the quadriceps. It’s favorite among lifters who prefer the seated position to standing with a load on the spine.', 'EotSw18oR9w').
exercise_kb('EX_120', 'reverse_nordic', 1, [], ['high_knee_torque'], [], ['foundation', 'build_and_burn', 'build_and_burn', 'recomposition'], ['quads'], ['core'], ['a_tier'], 'quad_isolation', false, 'The reverse lunge is a lower-body exercise targeting the quads, glutes, and hamstrings. The reverse lunge places more emphasis on the glutes than other lunge variations.', 'GtBxjoLlHyA').
exercise_kb('EX_121', 'barbell_hip_thrust', 2, ['barbell', 'bench', 'bar_pad'], ['pelvic_pressure'], [], ['foundation', 'recomposition', 'recomposition', 'hypertrophy_volume', 'strength_block'], ['glutes'], ['hamstrings'], ['b_tier'], 'glute_isolation', true, 'The barbell hip thrust is an exercise that engages the posterior chain, particular the glutes. It involves fully extending your hips while holding a weighted barbell across the midsection.', 'W86oVlnLqY4').
exercise_kb('EX_122', 'glute_bridge', 1, [], [], ['lower_back_activation'], ['foundation', 'build_and_burn', 'peak_recomposition'], ['glutes'], ['lower_back'], ['b_tier'], 'glute_isolation', false, 'The glute bridge is a popular lower-body bodyweight exercise that primarily targets the glutes, but also activates the lower back and hamstrings. It can be performed with body weight alone, or with added resistance such as barbells, dumbbells, or bands. It can be performed for time or reps and works perfectly in a dynamic warm-up for lower-body training, but can also be performed for glute activation anytime.', 'LORVjN2bg5o').
exercise_kb('EX_123', 'cable_hip_abduction', 2, ['cable_machine', 'ankle_strap'], [], [], ['build_and_burn', 'recomposition', 'recomposition', 'hypertrophy_volume'], ['glutes'], [], ['b_tier'], 'glute_isolation', false, 'Description coming soon.', 'sFQtAuiVwyo').
exercise_kb('EX_124', 'curtsy_lunge', 1, ['dumbbells'], ['lateral_knee_strain'], [], ['build_and_burn', 'build_and_burn', 'peak_metabolic'], ['glutes', 'quads'], ['adductors'], ['b_tier'], 'unilateral_leg', true, 'The curtsy lunge is a lower-body bodyweight movement that targets the muscles of the hips and glutes. It is usually performed for moderate to high reps, at least 8-12 reps per leg.', 'WAW-2ehQ1GM').
exercise_kb('EX_125', 'conventional_deadlift', 2, ['barbell', 'weight_plates'], ['spinal_compression', 'lumbar_shear'], [], ['foundation', 'strength_block', 'strength_block'], ['glutes', 'hamstrings', 'lower_back'], ['lats', 'core', 'forearms'], ['b_tier'], 'hinge_pattern', true, 'The barbell deadlift is a compound exercise used to develop overall strength and size in the posterior chain. It is a competition lift in the sport of powerlifting, but is also considered a classic benchmark of overall strength. When performed with the hands outside the knees, it is often called a "conventional" deadlift. When the feet are wide and the hands are inside the knees, it is a sumo deadlift.', 'ZaTM37cfiDs').
exercise_kb('EX_126', 'sumo_deadlift', 2, ['barbell', 'weight_plates'], ['hip_mobility_strain', 'lumbar_shear'], [], ['foundation', 'strength_block', 'strength_block'], ['glutes', 'quads', 'adductors'], ['lower_back', 'core'], ['b_tier'], 'hinge_pattern', true, 'The sumo deadlift is a compound movement in which the feet are set in a wide stance with toes pointed out and grip is placed inside of the legs. It is allowed to be performed instead of conventional deadlifts in most powerlifting competitions. The sumo deadlift targets the hamstrings, glutes, and upper back/traps, but also has a greater emphasis on stretching and strengthening the adductor and hip muscles due to the wide stance.', 'e7oLkRlT2CQ').
exercise_kb('EX_127', 'cable_pull_through', 2, ['cable_machine', 'rope_attachment'], [], [], ['build_and_burn', 'recomposition', 'recomposition', 'hypertrophy_volume'], ['glutes', 'hamstrings'], ['lower_back'], ['b_tier'], 'hinge_pattern', true, 'Description coming soon.', 'SuTI-n84ezA').
exercise_kb('EX_128', 'lunge', 1, ['dumbbells'], ['knee_torque'], [], ['foundation', 'build_and_burn', 'build_and_burn'], ['quads', 'glutes'], ['core'], ['b_tier'], 'unilateral_leg', true, 'The stationary bike is a popular cardio machine found in most commercial gyms. Along with burning a ton of calories, the stationary bike also helps develop the lower body. Stationary bikes come in multiple variations, ranging from ones that resemble riding a bike, to recumbent bikes, to fan bikes that work both the arms and the legs. No matter the variation, a stationary bike can work well at higher speeds for interval-style conditioning training, but also works well at slower paces for steady-state cardio.', '1cS-6KsJW9g').
exercise_kb('EX_129', 'goblet_squat', 1, ['dumbbells'], [], ['squat_mechanics_training'], ['foundation', 'build_and_burn', 'build_and_burn', 'peak_recomposition'], ['quads'], ['core', 'glutes'], ['b_tier'], 'squat_pattern', true, 'The goblet squat is a popular lower-body exercise where you hold a kettlebell or dumbbell in front of your chest as if you are supporting a heavy cup or goblet. It can help lifters of all levels improve their squat technique and hip mobility, but can also work as a muscle-building or strength accessory movement for experienced athletes. It also works well in combinations, complexes, and flows with other kettlebell movements like swings, presses, and cleans.', 'lRYBbchqxtI').
exercise_kb('EX_130', 'sissy_squat', 2, ['sissy_squat_bench'], [], [], ['recomposition', 'recomposition', 'hypertrophy_volume'], ['quads'], ['core'], ['b_tier'], 'quad_isolation', false, 'The sissy squat is a bodyweight squat variation that involves letting the knees travel far over the toes, placing an extreme stretch on the quads. This movement targets the quad muscles directly and can be performed in partial or full ranges of motion based on knee health and pain.', 'AYN-U5nZieY').
exercise_kb('EX_201', 'machine_chest_press', 2, ['chest_press_machine'], [], [], ['foundation', 'build_and_burn', 'build_and_burn', 'recomposition', 'recomposition', 'hypertrophy_volume'], ['chest'], ['front_delts', 'triceps'], ['s_plus'], 'horizontal_press', true, 'The machine chest press is a machine-based exercise targeting the chest. It approximates the motion of a bench press but is usually performed facing forward and seated upright. Many machines offer multiple grip options, such as overhand, neutral (palms facing), or underhand. The chest press is often performed for moderate to high reps, such as 8-12 reps per set or more, as part of a pre-exhaust or muscle-building upper-body workout.', 'Qu7-ceCvq7w').
exercise_kb('EX_202', 'seated_cable_pec_fly', 2, ['cable_machine', 'bench'], [], [], ['build_and_burn', 'recomposition', 'recomposition', 'hypertrophy_volume'], ['chest'], [], ['s_tier'], 'chest_isolation', false, 'The seated cable chest fly is an isolation movement that uses a cable stack and an upright bench to target the pectoral muscles. Being able to brace against a seat can help you stabilize your torso and focus on isolating the pecs, feeling them stretch and contract. It is usually used in combination with other presses or flyes to target the chest from different angles.', 'Tymt8yZnJYE').
exercise_kb('EX_203', 'flat_bench_press', 2, ['barbell', 'bench', 'weight_plates'], ['shoulder_anterior'], [], ['foundation', 'recomposition', 'recomposition', 'strength_block', 'hypertrophy_volume', 'strength_block'], ['chest'], ['front_delts', 'triceps'], ['a_tier'], 'horizontal_press', true, 'The bench press is a popular barbell exercise that builds strength and muscle in the chest, triceps, and shoulders. It is a popular way to measure overall upper-body strength, and is contested in the sport of powerlifting. When many people think of lifting, the bench press is often the first exercise that comes to mind. It can be performed for low reps for strength, higher reps for muscle, or for higher reps to build or measure strength endurance, like in the 225-pound bench press rep test in the NFL combine.', 'hWbUlkb5Ms4').
exercise_kb('EX_204', 'incline_bench_press', 2, ['barbell', 'incline_bench', 'weight_plates'], ['shoulder_anterior'], [], ['foundation', 'recomposition', 'recomposition', 'strength_block', 'hypertrophy_volume', 'strength_block'], ['upper_chest', 'front_delts'], ['triceps'], ['a_tier', 'a_tier'], 'horizontal_press', true, 'The incline bench press is a popular barbell exercise targeting the chest muscles, particularly the upper pectoral muscles. While it can be a strength-focused movement, it is usually performed for moderate to high reps, such as 8-12 reps per set or more, as part of upper-body or chest-focused training.', '98HWfiRonkE').
exercise_kb('EX_205', 'flat_db_press', 1, ['dumbbells', 'bench'], [], [], ['build_and_burn', 'build_and_burn', 'recomposition', 'recomposition', 'hypertrophy_volume', 'strength_block'], ['chest'], ['front_delts', 'triceps'], ['a_tier'], 'horizontal_press', true, 'The seated dumbbell shoulder pressis an exercise for building muscle and strengthening the shoulders, particularly but not exclusively the front heads. The triceps also assist. Some lifters feel that using dumbbells versus a barbell reduced injury risk.', 'o7TvO377OqA').
exercise_kb('EX_206', 'incline_db_press', 1, ['dumbbells', 'incline_bench'], [], [], ['build_and_burn', 'build_and_burn', 'recomposition', 'recomposition', 'hypertrophy_volume', 'strength_block'], ['upper_chest', 'front_delts'], ['triceps'], ['a_tier', 'a_tier'], 'horizontal_press', true, 'The incline dumbbell bench press is an upper body exercise targeting the upper pectoral muscles.', '8fXfwG4ftaQ').
exercise_kb('EX_207', 'dips', 2, ['dip_station'], ['shoulder_anterior', 'sternum_pressure'], [], ['foundation', 'recomposition', 'recomposition', 'hypertrophy_volume', 'strength_block'], ['chest', 'lower_chest'], ['triceps', 'front_delts'], ['a_tier'], 'vertical_press', true, 'Description coming soon.', 'CrbIq-T-h8I').
exercise_kb('EX_208', 'smith_machine_press_flat_incline', 2, ['smith_machine', 'bench'], [], [], ['recomposition', 'recomposition', 'hypertrophy_volume', 'strength_block'], ['chest'], ['front_delts', 'triceps'], ['a_tier'], 'horizontal_press', true, 'The Smith machine leg press is a machine-based movement that targets the quads, glutes, and hamstrings. It can serve as a substitute for the leg press or be programmed similarly to the leg press. It is usually performed for moderate to high reps, such as 8-12 reps per set or more, as part of lower-body training. If your Smith machine has safety bars, set them at a height that allows you a full range of motion while giving adequate protection from the weight potentially falling.', 'VXaBbUYMfIs').
exercise_kb('EX_209', 'cable_crossover', 2, ['cable_machine'], ['shoulder_anterior_stretch'], [], ['build_and_burn', 'recomposition', 'recomposition', 'hypertrophy_volume'], ['chest'], [], ['a_tier'], 'chest_isolation', false, 'The cable cross-over is an isolation movement that uses a cable stack to build bigger and stronger pectoral muscles. Since it''s done using adjustable pulleys, you can target different parts of your chest by setting the pulleys at different levels. It is common in upper body and chest-focused muscle-building workouts, often as a pre-exhaust at the beginning of a workout, or a finishing movement at the end. It is often in combination with other presses or flyes to target the chest from different angles.', 'NyO5y-G5Ceg').
exercise_kb('EX_210', 'pec_deck_machine', 2, ['pec_deck_machine'], ['shoulder_anterior_stretch'], [], ['recomposition', 'recomposition', 'hypertrophy_volume'], ['chest'], [], ['a_tier'], 'chest_isolation', false, 'The dip machine is a machine exercise that mimics a triceps dip, a bodyweight exercise performed on parallel bars or on a pull-up and dip station. It targets the triceps first, but also stretches and strengthens the chest and shoulders. Dips with a triceps focus are usually performed with an upright torso, the knees bent and crossed, and the arms close to the body. Dips can be performed for low reps for strength or higher reps for muscle growth.', 'fgXSA2-o0NM').
exercise_kb('EX_211', 'db_fly', 1, ['dumbbells', 'bench'], ['shoulder_anterior_stretch', 'bicep_tendon_stretch'], [], ['recomposition', 'recomposition', 'hypertrophy_volume'], ['chest'], [], ['a_tier'], 'chest_isolation', false, 'The dumbbell chest fly is a popular exercise that targets the pectoral or chest muscles. It attempts to isolate the chest muscles, stretching and contracting them while limiting involvement of the shoulders. Unlike a press, where the elbows bend and flex, flyes should keep a relatively consistent elbow angle. The motion is sometimes compared to "hugging a tree." Dumbbell flyes are usually performed for moderate to high reps, such as 8-12 reps per set or more, as part of a chest or upper-body focused workout.', 'rk8YayRoTRQ').
exercise_kb('EX_212', 'deficit_push_up', 1, ['push_up_handles_or_plates'], ['shoulder_anterior_stretch'], [], ['build_and_burn', 'build_and_burn', 'recomposition', 'recomposition', 'peak_metabolic'], ['chest'], ['triceps', 'front_delts'], ['a_tier'], 'horizontal_press', true, 'The feet-elevated push-up is a variation on the push-up, a body-weight standard. The feet are elevated, so that your body is aligned at an angle to the floor rather than parallel.', 'Ed38v7kcgXM').
exercise_kb('EX_213', 'cable_press_around', 2, ['cable_machine'], [], [], ['recomposition', 'recomposition', 'hypertrophy_volume'], ['chest'], [], ['a_tier'], 'chest_isolation', false, 'The standing calf raise is a popular movement to target the calf muscles of the lower leg, and in particular the gastrocnemius muscles. When unweighted, it is usually performed for high reps or for time.', 'HpWKCfbXsVk').
exercise_kb('EX_214', 'guillotine_press_db', 1, ['dumbbells', 'bench'], ['shoulder_impingement'], [], ['recomposition', 'recomposition', 'hypertrophy_volume'], ['upper_chest'], ['front_delts'], ['a_tier'], 'horizontal_press', true, 'The incline dumbbell row is an upper-body exercise targeting the lats (latissimus dorsi) and upper-back muscles, as well as the biceps. Performing it on an incline bench helps target the lower lats in particular. Dumbbell row variations are usually performed for moderate to high reps, such as 8-12 reps per set or more, as part of the upper-body or back-focused portion of a workout.', '0lD_IhpSWfE').
exercise_kb('EX_215', 'decline_bench_press', 2, ['barbell', 'decline_bench'], [], [], ['recomposition', 'recomposition', 'hypertrophy_volume', 'strength_block'], ['lower_chest'], ['triceps'], ['b_tier'], 'horizontal_press', true, 'Description coming soon.', 'a-UFQE4oxWY').
exercise_kb('EX_216', 'banded_push_up', 1, ['resistance_bands'], [], [], ['build_and_burn', 'build_and_burn', 'recomposition', 'recomposition'], ['chest'], ['triceps', 'core'], ['b_tier'], 'horizontal_press', true, 'The band push-up is a progression of the popular bodyweight version of the exercise commonly used in military and tactical physical fitness tests. Adding the dynamic resistance of the band matches the strength curve of the push-up and helps build upper-body muscle and strength, emphasizing the chest, triceps, and shoulders, but also working the upper back and core.', 'sspvzK7cWQk').
